create table songs (
    song_id      number generated by default as identity not null enable,
    title        varchar2(100 byte) not null enable,
    artist       varchar2(100 byte) not null enable,
    album        varchar2(100 byte),
    genre        varchar2(50 byte),
    duration_sec number(4, 0),
    release_year number(4, 0)
);

alter table songs add primary key ( song_id )
    using index enable;


